previewCss:
.darma-loader-darma-custom-526 {color: var(--loader-color, #be123c);
  --loader-secondary-color: var(--loader-secondary-color, #fda4af);
  --loader-bg: var(--loader-bg, #ffffff);
   height: 30px;
   aspect-ratio: 2;
   display: grid;
   background: radial-gradient(farthest-side,currentColor 15%,#0000 18%)0 0/50% 100%, radial-gradient(50% 100% at 50% 160%,currentColor 95%,#0000) 0 0 /50% 50%, radial-gradient(50% 100% at 50% -60%,currentColor 95%,#0000) 0 100%/50% 50%;
   background-repeat: repeat-x;
   animation: darma-loader-darma-custom-526-l2 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-526-l2  {
  0%, 15% {background-position:0 0,0 0,0 100%}
20%, 40% {background-position:5px 0,0 0,0 100%}
45%, 55% {background-position:0 0,0 0,0 100%}
60%, 80%{background-position:-5px 0,0 0,0 100%}
85%, 100% {background-position:0 0,0 0,0 100%}
}

